  video_desc:        { ko:"범죄예방 체험관을 영상으로 먼저 확인해보세요", en:"Watch the intro video before you start", ja:"始める前に紹介動画をご覧ください", zh:"开始前先观看介绍视频", vi:"Xem video giới thiệu trước khi bắt đầu", es:"Mira el video introductorio antes de comenzar", de:"Schauen Sie sich das Einführungsvideo an, bevor Sie beginnen", fr:"Regardez la vidéo d'introduction avant de commencer", hi:"शुरू करने से पहले परिचय वीडियो देखें", pt:"Assista ao vídeo de introdução antes de começar" },
  how_title:         { ko:"어떻게 체험하나요?", en:"How Does It Work?", ja:"どうやって体験しますか？", zh:"如何体验？", vi:"Cách trải nghiệm như thế nào?", es:"¿Cómo funciona?", de:"Wie funktioniert es?", fr:"Comment ça fonctionne?", hi:"यह कैसे काम करता है?", pt:"Como funciona?" },
  step1_title:       { ko:"시나리오 선택", en:"Choose a Scenario", ja:"シナリオ選択", zh:"选择场景", vi:"Chọn kịch bản", es:"Elige un escenario", de:"Szenario auswählen", fr:"Choisir un scénario", hi:"एक परिदृश्य चुनें", pt:"Escolha um cenário" },
  step1_desc:        { ko:"보이스피싱, 투자사기, 불법도박 등 9가지 실제 범죄 유형 중 하나를 선택합니다.", en:"Choose from 9 real crime types: voice phishing, investment fraud, illegal gambling, and more.", ja:"ボイスフィッシング、投資詐欺、違法賭博など9種類から選択します。", zh:"从电话诈骗、投资诈骗、非法赌博等9种真实犯罪类型中选择。", vi:"Chọn từ 9 loại tội phạm thực tế.", es:"Elige entre 9 tipos de crimen real.", de:"Wählen Sie aus 9 echten Verbrechenstypen.", fr:"Choisissez parmi 9 types de crimes réels.", hi:"9 वास्तविक अपराध प्रकारों में से एक चुनें।", pt:"Escolha entre 9 tipos reais de crime." },
  step2_title:       { ko:"AI와 대화 체험", en:"Chat with AI Scammer", ja:"AIと会話体験", zh:"与AI骗子对话", vi:"Trò chuyện với AI lừa đảo", es:"Chatea con el estafador IA", de:"Mit KI-Betrüger chatten", fr:"Discuter avec l'arnaqueur IA", hi:"AI धोखेबाज से चैट करें", pt:"Converse com o golpista IA" },
  step2_desc:        { ko:"실제 사기범처럼 행동하는 AI와 대화하며 범죄 수법을 직접 경험합니다. 실제 돈은 나가지 않습니다.", en:"Chat with an AI acting like a real scammer. No real money involved.", ja:"実際の詐欺師のように行動するAIと会話します。実際のお金は出ません。", zh:"与像真实骗子一样行动的AI对话。不涉及真实金钱。", vi:"Trò chuyện với AI như kẻ lừa đảo thật. Không có tiền thật.", es:"Chatea con una IA como estafador real. Sin dinero real.", de:"Chatten Sie mit einer KI wie ein echter Betrüger. Kein echtes Geld.", fr:"Discutez avec une IA comme un vrai escroc. Pas de vrai argent.", hi:"एक असली धोखेबाज जैसी AI से चैट करें। कोई असली पैसा नहीं।", pt:"Converse com uma IA como um golpista real. Sem dinheiro real." },
  step3_title:       { ko:"범죄 수법 확인", en:"Review Crime Tactics", ja:"犯罪手口確認", zh:"查看犯罪手法", vi:"Xem lại thủ thuật tội phạm", es:"Revisa las tácticas criminales", de:"Verbrechenstaktiken überprüfen", fr:"Revoir les tactiques criminelles", hi:"अपराध की तकनीकें देखें", pt:"Revise as táticas criminosas" },
  step3_desc:        { ko:"체험 후 해당 범죄의 수법, 예방법, 신고 번호를 상세히 알려드립니다.", en:"After the experience, we explain the crime tactics, prevention tips, and report numbers in detail.", ja:"体験後、犯罪手口、予防法、通報番号を詳しくお伝えします。", zh:"体验后，我们将详细介绍犯罪手法、预防方法和举报电话。", vi:"Sau trải nghiệm, chúng tôi giải thích chi tiết thủ thuật và cách phòng ngừa.", es:"Tras la experiencia, explicamos las tácticas y números de denuncia.", de:"Nach der Erfahrung erklären wir die Taktiken und Präventions-Tipps.", fr:"Après l'expérience, nous expliquons les tactiques et conseils de prévention.", hi:"अनुभव के बाद, हम अपराध की तकनीकों और रोकथाम के सुझावों को विस्तार से बताते हैं।", pt:"Após a experiência, explicamos as táticas e dicas de prevenção em detalhes." },
